external_knowledge:
- 'popular active package categories' refers to types with more than 10 active packages;
- 'detailed descriptions' implies that the package has a non-null description;
- 'excluding those with sparse entries' means excluding types with 10 or fewer packages.

sql:
SELECT user_id, COUNT(*) AS total_comments
FROM package_comments
GROUP BY user_id;

SELECT packages.package_id, package_types.type_name
FROM packages
INNER JOIN package_types ON packages.type = package_types.type_id;

SELECT team_id, COUNT(user_id) AS total_users 
FROM team_memberships 
GROUP BY team_id;

SELECT comment_id, user_id, comment_text, created_at
FROM package_comments
WHERE package_id = 123;

SELECT COUNT(d.dependency_id) AS num_dependencies
FROM dependencies d
WHERE d.package_id = 'your_package_id';
